module bitwise_full_adder (
    input  A   ,
    input  B   ,
    input  CIN ,
    input  VPB ,
    input  VPWR,
    input  VGND,
    input  VNB ,
    output COUT,
    output SUM 
);

    assign SUM = (A ^ B) ^ CIN;
  wire temp1_(A & B) = (A & B);
  wire temp2_(CIN & (A ^ B)) = (CIN & (A ^ B));
  assign COUT = temp1_(A & B) | temp2_(CIN & (A ^ B));

endmodule
